<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Game;use App\Models\GameCategory;use Illuminate\Http\Request;use Illuminate\Support\Str;class GameController extends Controller{public function index(){$games=Game::with('category')->withCount('packages')->latest()->paginate(15);return view('admin.games.index',compact('games'));}public function create(){return view('admin.games.form',['game'=>new Game,'categories'=>GameCategory::where('is_active',1)->get()]);}public function store(Request $r){$d=$this->data($r);$d['slug']=$d['slug']?:Str::slug($d['name']);Game::create($d);return redirect()->route('admin.games.index')->with('success','Game saved.');}public function edit(Game $game){return view('admin.games.form',['game'=>$game,'categories'=>GameCategory::where('is_active',1)->get()]);}public function update(Request $r,Game $game){$d=$this->data($r,$game->id);$game->update($d);return redirect()->route('admin.games.index')->with('success','Game updated.');}private function data(Request $r,$id=null){$d=$r->validate(['category_id'=>'required|exists:game_categories,id','name'=>'required|max:191','slug'=>'nullable|max:191|unique:games,slug,'.$id,'image'=>'nullable|max:191','cover_3d'=>'nullable|max:191','description'=>'nullable','sort_order'=>'nullable|integer']);$d['requires_server_id']=$r->boolean('requires_server_id');$d['requires_player_id']=$r->boolean('requires_player_id');$d['is_active']=$r->boolean('is_active');return $d;}}
